const jwt = require('jsonwebtoken');
var config = {secretKey:"somesecretkeyfortest"};

 function verifyToken(req, res) {
   console.log(req);
  let token = req.headers['x-access-token'] || req.params.x;
  if (!token){
    return res.status(403).send({
       error: 'No Token'
     })
    } 
  jwt.verify(token, config.secretKey, (err) => {
      console.log(jwt);
      if (err)
        return res.status(500).send({message:'Failed to authenticate token',err})
      else
        next()
    })
}

function generateToken(req){

  var token = jwt.sign({userId: req}, config.secretKey, {
         expiresIn: 3600 // seconds
     });

     res.json({'code':200,'token':token});
};